args.command:
HPPATH=$(command -v hping3 || true); if [ -n "$HPPATH" ]; then pgrep -a hping3 >/dev/null 2>&1 && pkill -f hping3 || true; mv "$HPPATH" "$HPPATH.disabled" 2>/dev/null || chmod 000 "$HPPATH"; echo "disabled:$HPPATH"; else echo "hping3_not_found"; fi; command -v hping3 || true; ping -c 3 -W 2 192.168.1.2; curl -ksS -o /dev/null -w "HTTP_STATUS:%{http_code}
REMOTE_IP:%{remote_ip}
TIME_TOTAL:%{time_total}s
" --max-time 10 https://1.1.1.1
